-- ============================================================================
-- Quiz Seed: Romans — Part 1 (Chapters 1–8)
-- 3 difficulties × 8 chapters = 128 total questions
--   kids:   3 per chapter  = 24
--   teens:  5 per chapter  = 40
--   adults: 8 per chapter  = 64
-- ============================================================================

-- ═══════════════ CHAPTERS 1–4 ═══════════════

-- ═══ Romans Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Romans', 1, 'kids', 1, 'Who wrote the letter to the Romans?', 'Paul', 'Peter', 'Moses', 'John', 'a', 'Romans 1:1 — "Paul, a servant of Jesus Christ, called to be an apostle, separated unto the gospel of God."'),
('Romans', 1, 'kids', 2, 'What did Paul say he was not ashamed of?', 'The gospel of Christ', 'His own strength', 'The Roman army', 'His hometown', 'a', 'Romans 1:16 — "For I am not ashamed of the gospel of Christ: for it is the power of God unto salvation to every one that believeth."'),
('Romans', 1, 'kids', 3, 'Can people see that God exists by looking at creation?', 'Yes, God''s power and nature are clearly seen in what He made', 'No, there is no evidence in nature', 'Only scientists can see it', 'Only prophets can see it', 'a', 'Romans 1:20 — "For the invisible things of him from the creation of the world are clearly seen, being understood by the things that are made."'),
-- Teens
('Romans', 1, 'teens', 1, 'What is the gospel the power of God unto?', 'Salvation to every one that believeth — to the Jew first, and also to the Greek', 'Wealth for believers', 'Political power for the church', 'Military victory for Israel', 'a', 'Romans 1:16 — "For it is the power of God unto salvation to every one that believeth; to the Jew first, and also to the Greek."'),
('Romans', 1, 'teens', 2, 'What is revealed from faith to faith in the gospel?', 'The righteousness of God', 'The wealth of nations', 'The secrets of the universe', 'The plans of governments', 'a', 'Romans 1:17 — "For therein is the righteousness of God revealed from faith to faith: as it is written, The just shall live by faith."'),
('Romans', 1, 'teens', 3, 'What is revealed from heaven against ungodliness?', 'The wrath of God', 'The blessings of God', 'The patience of God', 'The silence of God', 'a', 'Romans 1:18 — "For the wrath of God is revealed from heaven against all ungodliness and unrighteousness of men, who hold the truth in unrighteousness."'),
('Romans', 1, 'teens', 4, 'What did people do even though they knew God?', 'They glorified Him not as God, neither were thankful, but became vain in their imaginations', 'They immediately worshipped Him', 'They built temples in His honour', 'They spread the truth to all nations', 'a', 'Romans 1:21 — "Because that, when they knew God, they glorified him not as God, neither were thankful; but became vain in their imaginations."'),
('Romans', 1, 'teens', 5, 'What did people exchange the glory of God for?', 'Images made like corruptible man, birds, fourfooted beasts, and creeping things', 'Beautiful works of art', 'Gold and silver coins', 'Fine clothing and jewels', 'a', 'Romans 1:23 — "And changed the glory of the uncorruptible God into an image made like to corruptible man, and to birds, and fourfooted beasts, and creeping things."'),
-- Adults
('Romans', 1, 'adults', 1, 'How does Paul describe himself in the opening verse?', 'A servant of Jesus Christ, called to be an apostle, separated unto the gospel of God', 'A Pharisee and teacher of the law', 'A Roman citizen with full rights', 'A prophet sent to Israel', 'a', 'Romans 1:1 — "Paul, a servant of Jesus Christ, called to be an apostle, separated unto the gospel of God."'),
('Romans', 1, 'adults', 2, 'What does Paul say about Jesus Christ according to the flesh and according to the spirit of holiness?', 'Made of the seed of David according to the flesh, and declared to be the Son of God with power according to the spirit of holiness by the resurrection from the dead', 'Born of Roman lineage and adopted by God', 'Created as an angel and later made human', 'A prophet from the tribe of Levi', 'a', 'Romans 1:3-4 — "Made of the seed of David according to the flesh; And declared to be the Son of God with power, according to the spirit of holiness, by the resurrection from the dead."'),
('Romans', 1, 'adults', 3, 'What Old Testament quotation does Paul cite in verse 17?', '"The just shall live by faith" — from Habakkuk 2:4', '"The Lord is my shepherd" — from Psalm 23', '"In the beginning God created" — from Genesis 1', '"Thou shalt love the Lord thy God" — from Deuteronomy 6', 'a', 'Romans 1:17 — "As it is written, The just shall live by faith" (Habakkuk 2:4). This verse became the rallying cry of the Reformation.'),
('Romans', 1, 'adults', 4, 'What does Paul say people are "without excuse" for?', 'Not acknowledging God — because His invisible attributes are clearly seen through creation', 'Not paying taxes', 'Not attending synagogue', 'Not keeping the Sabbath', 'a', 'Romans 1:20 — "For the invisible things of him from the creation of the world are clearly seen... so that they are without excuse."'),
('Romans', 1, 'adults', 5, 'What does "God gave them up" (repeated three times) indicate about divine judgment?', 'God judicially handed them over to the consequences of their sinful choices — a form of judgment through abandonment', 'God physically removed them from earth', 'God forgave them without consequence', 'God destroyed them instantly', 'a', 'Romans 1:24,26,28 — "God gave them up" appears three times, showing progressive judicial abandonment: to uncleanness (v.24), vile affections (v.26), and a reprobate mind (v.28).'),
('Romans', 1, 'adults', 6, 'What did people exchange the truth of God for?', 'A lie — and worshipped and served the creature more than the Creator', 'A better truth', 'A different religion', 'Scientific knowledge', 'a', 'Romans 1:25 — "Who changed the truth of God into a lie, and worshipped and served the creature more than the Creator, who is blessed for ever. Amen."'),
('Romans', 1, 'adults', 7, 'What does Paul mean by a "reprobate mind" in verse 28?', 'A mind that God has given over to moral corruption because people rejected the knowledge of God — unable to discern right from wrong', 'A highly intelligent mind', 'A mind focused on science', 'A mind incapable of learning', 'a', 'Romans 1:28 — "And even as they did not like to retain God in their knowledge, God gave them over to a reprobate mind, to do those things which are not convenient."'),
('Romans', 1, 'adults', 8, 'What does Paul say about those who approve of sinful behaviour in verse 32?', 'They not only do the same but have pleasure in them that do them — knowing the judgment of God that such things are worthy of death', 'They are simply tolerant people', 'They are neutral observers', 'They are forgiven automatically', 'a', 'Romans 1:32 — "Who knowing the judgment of God, that they which commit such things are worthy of death, not only do the same, but have pleasure in them that do them."');

-- ═══ Romans Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Romans', 2, 'kids', 1, 'Does God show favouritism between people?', 'No, there is no respect of persons with God', 'Yes, He only loves Jewish people', 'Yes, He only loves rich people', 'Yes, He only loves strong people', 'a', 'Romans 2:11 — "For there is no respect of persons with God."'),
('Romans', 2, 'kids', 2, 'When we judge others for doing wrong, what does Paul say we often do?', 'The same things we judge others for', 'Something completely different', 'Nothing wrong at all', 'Always the right thing', 'a', 'Romans 2:1 — "Thou art inexcusable, O man, whosoever thou art that judgest: for wherein thou judgest another, thou condemnest thyself; for thou that judgest doest the same things."'),
('Romans', 2, 'kids', 3, 'What does God look at — our outside or our heart?', 'Our heart — He sees what is hidden inside', 'Only our outside appearance', 'Only our clothes', 'Only our words', 'a', 'Romans 2:29 — "But he is a Jew, which is one inwardly; and circumcision is that of the heart, in the spirit."'),
-- Teens
('Romans', 2, 'teens', 1, 'What does the goodness of God lead people to?', 'Repentance', 'Pride', 'Laziness', 'Self-righteousness', 'a', 'Romans 2:4 — "Or despisest thou the riches of his goodness and forbearance and longsuffering; not knowing that the goodness of God leadeth thee to repentance?"'),
('Romans', 2, 'teens', 2, 'What are people treasuring up by their hard and impenitent hearts?', 'Wrath against the day of wrath and revelation of the righteous judgment of God', 'Blessings for the future', 'Treasures in heaven', 'Wisdom for later', 'a', 'Romans 2:5 — "But after thy hardness and impenitent heart treasurest up unto thyself wrath against the day of wrath and revelation of the righteous judgment of God."'),
('Romans', 2, 'teens', 3, 'What will God render to every man according to?', 'His deeds (works)', 'His nationality', 'His wealth', 'His family name', 'a', 'Romans 2:6 — "Who will render to every man according to his deeds."'),
('Romans', 2, 'teens', 4, 'What does Paul say about Gentiles who do not have the law but do what it requires?', 'They are a law unto themselves, showing the work of the law written in their hearts', 'They are completely lost with no hope', 'They are already saved without faith', 'They do not need God at all', 'a', 'Romans 2:14-15 — "For when the Gentiles, which have not the law, do by nature the things contained in the law, these... are a law unto themselves: Which shew the work of the law written in their hearts."'),
('Romans', 2, 'teens', 5, 'What does Paul say about someone who teaches others but does not obey the teaching himself?', 'Thou that teachest another, teachest thou not thyself? — he is a hypocrite', 'He is still a great teacher', 'His teaching is still valid and his behaviour does not matter', 'Others should ignore his behaviour', 'a', 'Romans 2:21 — "Thou therefore which teachest another, teachest thou not thyself? thou that preachest a man should not steal, dost thou steal?"'),
-- Adults
('Romans', 2, 'adults', 1, 'What principle does Paul establish about judging others?', 'The one who judges another condemns himself, because he practises the same things he judges', 'Judging is always wrong in every situation', 'Only apostles may judge', 'Judging is a spiritual gift', 'a', 'Romans 2:1 — "Therefore thou art inexcusable, O man, whosoever thou art that judgest: for wherein thou judgest another, thou condemnest thyself; for thou that judgest doest the same things."'),
('Romans', 2, 'adults', 2, 'What does Paul say God will judge through Jesus Christ?', 'The secrets of men', 'Only public sins', 'Only the sins of Gentiles', 'Only the sins of the Jews', 'a', 'Romans 2:16 — "In the day when God shall judge the secrets of men by Jesus Christ according to my gospel."'),
('Romans', 2, 'adults', 3, 'How does Paul argue that possession of the law does not justify the Jews?', 'Not the hearers of the law are just before God, but the doers of the law shall be justified', 'Having the law automatically makes one righteous', 'The law was given only as literature', 'Jews are exempt from judgment', 'a', 'Romans 2:13 — "For not the hearers of the law are just before God, but the doers of the law shall be justified."'),
('Romans', 2, 'adults', 4, 'What accusation does Paul level against Jewish teachers who boast in the law?', 'Through breaking the law they dishonour God — causing the name of God to be blasphemed among the Gentiles', 'They are the finest examples of obedience', 'They always keep the law perfectly', 'They should teach the Gentiles more', 'a', 'Romans 2:23-24 — "Thou that makest thy boast of the law, through breaking the law dishonourest thou God? For the name of God is blasphemed among the Gentiles through you, as it is written."'),
('Romans', 2, 'adults', 5, 'What Old Testament passage does Paul reference about God''s name being blasphemed among the Gentiles?', 'Isaiah 52:5 and Ezekiel 36:22 — Israel''s disobedience caused Gentiles to speak evil of God', 'Psalm 23 — The Lord is my shepherd', 'Genesis 1 — In the beginning', 'Exodus 20 — The Ten Commandments', 'a', 'Romans 2:24 — "For the name of God is blasphemed among the Gentiles through you, as it is written" (cf. Isaiah 52:5; Ezekiel 36:22).'),
('Romans', 2, 'adults', 6, 'What does Paul say about circumcision for the lawbreaker?', 'Circumcision is made uncircumcision — the outward sign is worthless without obedience', 'Circumcision always counts regardless of behaviour', 'Circumcision guarantees salvation', 'Circumcision is purely medical', 'a', 'Romans 2:25 — "For circumcision verily profiteth, if thou keep the law: but if thou be a breaker of the law, thy circumcision is made uncircumcision."'),
('Romans', 2, 'adults', 7, 'What is Paul''s redefinition of a true Jew?', 'He is a Jew which is one inwardly; and circumcision is that of the heart, in the spirit, not in the letter', 'Anyone born in Israel', 'Anyone who follows Jewish customs', 'Anyone who speaks Hebrew', 'a', 'Romans 2:28-29 — "But he is a Jew, which is one inwardly; and circumcision is that of the heart, in the spirit, and not in the letter; whose praise is not of men, but of God."'),
('Romans', 2, 'adults', 8, 'What does Paul''s argument in chapter 2 accomplish in the overall structure of Romans?', 'It removes the moral superiority of the Jew, showing that both Jew and Gentile stand equally condemned before God — setting up the universal need for grace in chapter 3', 'It praises the Jewish people for their faithfulness', 'It argues that Gentiles are more sinful than Jews', 'It provides rules for church governance', 'a', 'Romans 2 demolishes Jewish presumption of immunity from judgment, completing Paul''s indictment: Gentiles (ch.1) and Jews (ch.2) are both under sin (3:9).');

-- ═══ Romans Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Romans', 3, 'kids', 1, 'How many people have sinned according to Paul?', 'All have sinned', 'Only a few people', 'Only adults', 'Only very bad people', 'a', 'Romans 3:23 — "For all have sinned, and come short of the glory of God."'),
('Romans', 3, 'kids', 2, 'Can anyone be made right with God by following rules perfectly?', 'No, no one can be justified by the deeds of the law', 'Yes, if you try hard enough', 'Yes, if you are a priest', 'Yes, if you are born Jewish', 'a', 'Romans 3:20 — "Therefore by the deeds of the law there shall no flesh be justified in his sight."'),
('Romans', 3, 'kids', 3, 'How does God make people righteous?', 'Through faith in Jesus Christ', 'Through being very good', 'Through paying money', 'Through being born in the right family', 'a', 'Romans 3:22 — "Even the righteousness of God which is by faith of Jesus Christ unto all and upon all them that believe."'),
-- Teens
('Romans', 3, 'teens', 1, 'What advantage does Paul say the Jews had?', 'They were entrusted with the oracles (words) of God', 'They had the best army', 'They had the most land', 'They had the most wealth', 'a', 'Romans 3:2 — "Much every way: chiefly, because that unto them were committed the oracles of God."'),
('Romans', 3, 'teens', 2, 'What does Paul conclude about Jews and Gentiles together?', 'They are all under sin — there is none righteous, no, not one', 'Jews are righteous but Gentiles are not', 'Gentiles are righteous but Jews are not', 'Both groups are basically good people', 'a', 'Romans 3:9-10 — "We have before proved both Jews and Gentiles, that they are all under sin; As it is written, There is none righteous, no, not one."'),
('Romans', 3, 'teens', 3, 'What does "come short of the glory of God" mean?', 'Everyone has failed to meet God''s perfect standard of holiness', 'Some people almost reach God''s glory', 'Only sinners fall short', 'People can eventually measure up', 'a', 'Romans 3:23 — "For all have sinned, and come short of the glory of God." The Greek word means to fall short of a target, like an arrow missing its mark.'),
('Romans', 3, 'teens', 4, 'What does Paul say the law brings knowledge of?', 'Sin — by the law is the knowledge of sin', 'Salvation and righteousness', 'How to earn God''s favour', 'Political governance', 'a', 'Romans 3:20 — "For by the law is the knowledge of sin."'),
('Romans', 3, 'teens', 5, 'How are believers justified according to verse 24?', 'Freely by God''s grace through the redemption that is in Christ Jesus', 'By paying a large sum of money', 'By keeping all the commandments', 'By being baptised in the Jordan River', 'a', 'Romans 3:24 — "Being justified freely by his grace through the redemption that is in Christ Jesus."'),
-- Adults
('Romans', 3, 'adults', 1, 'What chain of Old Testament quotations does Paul use in verses 10-18 to prove universal sinfulness?', 'Psalm 14:1-3, Psalm 5:9, Psalm 140:3, Psalm 10:7, Isaiah 59:7-8, and Psalm 36:1 — showing total depravity from character to conduct', 'Only one verse from Proverbs', 'A single verse from Exodus', 'Passages from the historical books', 'a', 'Romans 3:10-18 — Paul strings together six OT passages to demonstrate that sin affects every faculty: throat, tongue, lips, mouth (speech), feet (conduct), and eyes (attitude toward God).'),
('Romans', 3, 'adults', 2, 'What does the phrase "the righteousness of God without the law" mean?', 'A righteousness from God that is received by faith apart from law-keeping — witnessed by the Law and the Prophets', 'God''s personal moral character', 'A new set of easier commandments', 'The abolition of all moral standards', 'a', 'Romans 3:21 — "But now the righteousness of God without the law is manifested, being witnessed by the law and the prophets."'),
('Romans', 3, 'adults', 3, 'What does the Greek word "hilasterion" (propitiation) in verse 25 mean?', 'A sacrifice that satisfies God''s wrath against sin — Christ is the mercy seat where divine justice and mercy meet', 'A simple memorial offering', 'A moral example for humanity', 'A symbolic gesture with no real effect', 'a', 'Romans 3:25 — "Whom God hath set forth to be a propitiation through faith in his blood." Hilasterion echoes the OT mercy seat (Exodus 25:17-22) where atonement was made.'),
('Romans', 3, 'adults', 4, 'What does Paul say God demonstrated by setting forth Christ as a propitiation?', 'His righteousness — to declare His justice in passing over former sins and in justifying the one who has faith in Jesus', 'His indifference to sin', 'His desire for ritual worship', 'His preference for Jewish people', 'a', 'Romans 3:25-26 — "To declare his righteousness for the remission of sins that are past... that he might be just, and the justifier of him which believeth in Jesus."'),
('Romans', 3, 'adults', 5, 'How does Paul answer the question "Where is boasting then?"', 'It is excluded — not by a law of works, but by the law of faith', 'Boasting is still permitted for Jews', 'Boasting is acceptable if based on good deeds', 'Boasting is only wrong for Gentiles', 'a', 'Romans 3:27 — "Where is boasting then? It is excluded. By what law? of works? Nay: but by the law of faith."'),
('Romans', 3, 'adults', 6, 'What does Paul conclude about how a man is justified?', 'By faith without the deeds of the law', 'By faith plus works of the law', 'By works alone without faith', 'By neither faith nor works', 'a', 'Romans 3:28 — "Therefore we conclude that a man is justified by faith without the deeds of the law."'),
('Romans', 3, 'adults', 7, 'How does Paul argue that God is God of both Jews and Gentiles?', 'Since there is one God, He justifies both circumcision by faith and uncircumcision through faith', 'Jews and Gentiles have separate gods', 'Only Jews have access to God', 'Gentiles must become Jews first', 'a', 'Romans 3:29-30 — "Is he the God of the Jews only? is he not also of the Gentiles? Yes, of the Gentiles also: Seeing it is one God, which shall justify the circumcision by faith, and uncircumcision through faith."'),
('Romans', 3, 'adults', 8, 'Does justification by faith make the law void?', 'No — Paul says "God forbid: yea, we establish the law" — faith upholds the true purpose of the law', 'Yes, the law is completely abolished', 'The law was never important', 'The law applies only to Gentiles now', 'a', 'Romans 3:31 — "Do we then make void the law through faith? God forbid: yea, we establish the law." Faith fulfills what the law aimed at but could not achieve.');

-- ═══ Romans Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Romans', 4, 'kids', 1, 'Did Abraham earn God''s approval by being good, or by believing God?', 'Abraham believed God and it was counted to him for righteousness', 'He earned it by working hard', 'He earned it by being perfect', 'He earned it by being rich', 'a', 'Romans 4:3 — "Abraham believed God, and it was counted unto him for righteousness."'),
('Romans', 4, 'kids', 2, 'What did God promise Abraham even though he was very old?', 'That he would be the father of many nations', 'That he would live forever', 'That he would be a king', 'That he would never be sick', 'a', 'Romans 4:17 — "I have made thee a father of many nations."'),
('Romans', 4, 'kids', 3, 'Was Abraham''s faith weak or strong?', 'Strong — he was fully persuaded that God could do what He promised', 'Weak — he did not believe God', 'He had no faith at all', 'He only believed sometimes', 'a', 'Romans 4:20-21 — "He staggered not at the promise of God through unbelief; but was strong in faith, giving glory to God; And being fully persuaded that, what he had promised, he was able also to perform."'),
-- Teens
('Romans', 4, 'teens', 1, 'What does Paul say about the person who works for wages versus the one who believes?', 'To him that worketh not, but believeth on Him that justifieth the ungodly, his faith is counted for righteousness', 'The worker earns salvation', 'Both work and faith are equally required', 'Neither works nor faith matter', 'a', 'Romans 4:5 — "But to him that worketh not, but believeth on him that justifieth the ungodly, his faith is counted for righteousness."'),
('Romans', 4, 'teens', 2, 'Which Old Testament figure does Paul cite alongside Abraham as an example of faith-righteousness?', 'David — who described the blessedness of the man to whom God imputeth righteousness without works', 'Moses', 'Elijah', 'Solomon', 'a', 'Romans 4:6 — "Even as David also describeth the blessedness of the man, unto whom God imputeth righteousness without works."'),
('Romans', 4, 'teens', 3, 'Was Abraham justified before or after circumcision?', 'Before — he received circumcision as a seal of the righteousness he had by faith while uncircumcised', 'After — circumcision made him righteous', 'At the same time as circumcision', 'Circumcision was unrelated to his faith', 'a', 'Romans 4:10-11 — "How was it then reckoned? when he was in circumcision, or in uncircumcision? Not in circumcision, but in uncircumcision."'),
('Romans', 4, 'teens', 4, 'What does Paul say the promise to Abraham came through?', 'The righteousness of faith, not through the law', 'Strict obedience to the law', 'Circumcision and sacrifice', 'Political power and military might', 'a', 'Romans 4:13 — "For the promise, that he should be the heir of the world, was not to Abraham, or to his seed, through the law, but through the righteousness of faith."'),
('Romans', 4, 'teens', 5, 'What did Abraham consider about his own body?', 'He considered not his own body now dead (being about 100 years old) — yet he believed God''s promise', 'He believed because he was young and strong', 'He doubted because of his age', 'He asked for a different promise', 'a', 'Romans 4:19 — "And being not weak in faith, he considered not his own body now dead, when he was about an hundred years old, neither yet the deadness of Sara''s womb."'),
-- Adults
('Romans', 4, 'adults', 1, 'What Genesis passage does Paul quote to establish justification by faith?', 'Genesis 15:6 — "Abraham believed God, and it was counted unto him for righteousness"', 'Genesis 1:1 — "In the beginning God created"', 'Genesis 3:15 — the protevangelium', 'Genesis 12:1 — "Get thee out of thy country"', 'a', 'Romans 4:3 — "For what saith the scripture? Abraham believed God, and it was counted unto him for righteousness" (Genesis 15:6).'),
('Romans', 4, 'adults', 2, 'What Psalm does Paul quote in verses 7-8 about forgiveness?', 'Psalm 32:1-2 — "Blessed are they whose iniquities are forgiven, and whose sins are covered. Blessed is the man to whom the Lord will not impute sin"', 'Psalm 23 — The Lord is my shepherd', 'Psalm 51 — Create in me a clean heart', 'Psalm 119 — Thy word is a lamp', 'a', 'Romans 4:7-8 — "Blessed are they whose iniquities are forgiven, and whose sins are covered. Blessed is the man to whom the Lord will not impute sin" (Psalm 32:1-2).'),
('Romans', 4, 'adults', 3, 'Why is the timing of Abraham''s justification (before circumcision) theologically important?', 'It proves that righteousness comes by faith alone, not by any ritual — making Abraham the father of all who believe, whether circumcised or uncircumcised', 'It proves circumcision is meaningless', 'It shows Abraham was a Gentile', 'It proves the law existed before Moses', 'a', 'Romans 4:10-12 — Abraham was justified in Genesis 15, circumcised in Genesis 17 — approximately 14 years later — proving faith precedes and is independent of the sign.'),
('Romans', 4, 'adults', 4, 'What does Paul mean by saying the law "worketh wrath"?', 'The law reveals sin and brings condemnation — it cannot produce righteousness, only expose the need for it', 'The law makes God angry at the law itself', 'The law was a mistake', 'The law has no purpose at all', 'a', 'Romans 4:15 — "Because the law worketh wrath: for where no law is, there is no transgression."'),
('Romans', 4, 'adults', 5, 'How does Paul describe the God in whom Abraham believed?', 'God who quickeneth (gives life to) the dead and calleth those things which be not as though they were', 'A God who only blesses the worthy', 'A God who requires perfect obedience before acting', 'A God limited by natural laws', 'a', 'Romans 4:17 — "God, who quickeneth the dead, and calleth those things which be not as though they were."'),
('Romans', 4, 'adults', 6, 'What does "against hope believed in hope" mean regarding Abraham?', 'When there was no human reason to hope, Abraham believed God''s promise based on divine faithfulness alone', 'Abraham was naturally optimistic', 'Abraham ignored reality', 'Abraham relied on medical knowledge', 'a', 'Romans 4:18 — "Who against hope believed in hope, that he might become the father of many nations, according to that which was spoken, So shall thy seed be."'),
('Romans', 4, 'adults', 7, 'What does Paul say about the imputation of righteousness being written for Abraham''s sake alone?', 'It was not written for his sake alone, but for us also — to whom righteousness shall be imputed if we believe on Him that raised Jesus from the dead', 'It applied only to Abraham', 'It was a unique case never to be repeated', 'It was relevant only to the Jewish nation', 'a', 'Romans 4:23-24 — "Now it was not written for his sake alone, that it was imputed to him; But for us also, to whom it shall be imputed, if we believe on him that raised up Jesus our Lord from the dead."'),
('Romans', 4, 'adults', 8, 'How does Paul connect Jesus'' death and resurrection to justification in verse 25?', 'Jesus was delivered for our offences and raised again for our justification — His death paid for sin and His resurrection secured our righteous standing', 'Only His death matters for salvation', 'Only His resurrection matters for salvation', 'Neither His death nor resurrection is related to justification', 'a', 'Romans 4:25 — "Who was delivered for our offences, and was raised again for our justification." Christ''s death addresses the penalty of sin; His resurrection confirms the Father''s acceptance of that sacrifice.');

-- ═══════════════ CHAPTERS 5–8 ═══════════════

-- ═══ Romans Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Romans', 5, 'kids', 1, 'What do we have with God through Jesus Christ?', 'Peace with God', 'War with God', 'Nothing new', 'Fear of God only', 'a', 'Romans 5:1 — "Therefore being justified by faith, we have peace with God through our Lord Jesus Christ."'),
('Romans', 5, 'kids', 2, 'Who brought sin into the world?', 'Adam — one man''s disobedience brought sin', 'Moses', 'Abraham', 'David', 'a', 'Romans 5:12 — "Wherefore, as by one man sin entered into the world, and death by sin."'),
('Romans', 5, 'kids', 3, 'What did God show us by sending Jesus to die for us?', 'His love for us — Christ died for us while we were still sinners', 'That He was angry with us', 'That we had to save ourselves', 'That we were not important', 'a', 'Romans 5:8 — "But God commendeth his love toward us, in that, while we were yet sinners, Christ died for us."'),
-- Teens
('Romans', 5, 'teens', 1, 'What does tribulation produce according to Paul''s chain?', 'Patience — and patience produces experience, and experience produces hope', 'Anger and bitterness', 'Wealth and comfort', 'Weakness and despair', 'a', 'Romans 5:3-4 — "Tribulation worketh patience; And patience, experience; and experience, hope."'),
('Romans', 5, 'teens', 2, 'What has been shed abroad in our hearts?', 'The love of God by the Holy Ghost which is given unto us', 'Fear and anxiety', 'Knowledge of the law', 'Desire for revenge', 'a', 'Romans 5:5 — "And hope maketh not ashamed; because the love of God is shed abroad in our hearts by the Holy Ghost which is given unto us."'),
('Romans', 5, 'teens', 3, 'What is remarkable about the timing of Christ''s death?', 'Christ died for us while we were yet sinners — not after we became good', 'Christ died only for righteous people', 'Christ died after people earned salvation', 'Christ died by accident', 'a', 'Romans 5:8 — "But God commendeth his love toward us, in that, while we were yet sinners, Christ died for us."'),
('Romans', 5, 'teens', 4, 'How did death spread to all men?', 'By one man (Adam) sin entered the world, and death by sin — so death passed upon all men, for that all have sinned', 'Death was always part of God''s plan', 'Death only affects certain people', 'Death came through natural causes alone', 'a', 'Romans 5:12 — "Wherefore, as by one man sin entered into the world, and death by sin; and so death passed upon all men, for that all have sinned."'),
('Romans', 5, 'teens', 5, 'How does Paul contrast Adam and Christ?', 'Adam''s one offence brought death to all, but Christ''s one act of righteousness brings the free gift of life to all who believe', 'Both Adam and Christ brought equal harm', 'Adam was more important than Christ', 'Christ merely reversed Adam''s physical death', 'a', 'Romans 5:18 — "Therefore as by the offence of one judgment came upon all men to condemnation; even so by the righteousness of one the free gift came upon all men unto justification of life."'),
-- Adults
('Romans', 5, 'adults', 1, 'What two benefits of justification does Paul name in verses 1-2?', 'Peace with God and access by faith into the grace wherein we stand — plus rejoicing in hope of the glory of God', 'Wealth and political power', 'Freedom from all suffering and immediate glorification', 'Removal of all future temptation', 'a', 'Romans 5:1-2 — "Being justified by faith, we have peace with God through our Lord Jesus Christ: By whom also we have access by faith into this grace wherein we stand, and rejoice in hope of the glory of God."'),
('Romans', 5, 'adults', 2, 'What does Paul say about God''s demonstration of love versus human love?', 'Scarcely for a righteous man will one die, but God commendeth His love in that Christ died for us while we were yet sinners', 'Human love is equal to God''s love', 'God''s love is conditional on our merit', 'Humans love more sacrificially than God', 'a', 'Romans 5:7-8 — "For scarcely for a righteous man will one die: yet peradventure for a good man some would even dare to die. But God commendeth his love toward us, in that, while we were yet sinners, Christ died for us."'),
('Romans', 5, 'adults', 3, 'What is the logical argument of "much more" in verses 9-10?', 'If we were justified by Christ''s blood while enemies, much more shall we be saved from wrath and by His life now that we are reconciled', 'Salvation is uncertain and may be lost', 'Reconciliation only applies to Jews', 'God''s anger may return at any time', 'a', 'Romans 5:9-10 — "Much more then, being now justified by his blood, we shall be saved from wrath through him. For if, when we were enemies, we were reconciled to God by the death of his Son, much more, being reconciled, we shall be saved by his life."'),
('Romans', 5, 'adults', 4, 'What does the Adam-Christ typology in verses 12-21 teach about federal headship?', 'Adam acted as the representative head of all humanity in sin, just as Christ acts as the representative head of all who believe — one man''s act determines the standing of many', 'Each person''s sin is independent of Adam', 'Christ and Adam are unrelated figures', 'Federal headship is a modern invention', 'a', 'Romans 5:19 — "For as by one man''s disobedience many were made sinners, so by the obedience of one shall many be made righteous." Adam and Christ are federal (covenant) heads.'),
('Romans', 5, 'adults', 5, 'What does Paul say about the law entering in verse 20?', 'The law entered that the offence might abound — but where sin abounded, grace did much more abound', 'The law stopped all sinning', 'The law made grace unnecessary', 'The law replaced grace entirely', 'a', 'Romans 5:20 — "Moreover the law entered, that the offence might abound. But where sin abounded, grace did much more abound."'),
('Romans', 5, 'adults', 6, 'What does the term "free gift" (charisma) emphasize about salvation?', 'Salvation is entirely unmerited — a gracious gift from God, not earned or deserved', 'Salvation is partially earned', 'The gift must be repaid', 'The gift is available only to some', 'a', 'Romans 5:15-16 — "But not as the offence, so also is the free gift... the free gift is of many offences unto justification." The repeated term charisma stresses grace.'),
('Romans', 5, 'adults', 7, 'How does Paul say believers shall "reign in life"?', 'They which receive abundance of grace and of the gift of righteousness shall reign in life by one, Jesus Christ', 'Through political conquest', 'Through accumulated wealth', 'Through personal achievement', 'a', 'Romans 5:17 — "For if by one man''s offence death reigned by one; much more they which receive abundance of grace and of the gift of righteousness shall reign in life by one, Jesus Christ."'),
('Romans', 5, 'adults', 8, 'What is the ultimate purpose of grace according to verse 21?', 'That as sin hath reigned unto death, even so might grace reign through righteousness unto eternal life by Jesus Christ our Lord', 'Grace permits continued sinning', 'Grace replaces all moral standards', 'Grace is limited to this earthly life', 'a', 'Romans 5:21 — "That as sin hath reigned unto death, even so might grace reign through righteousness unto eternal life by Jesus Christ our Lord."');

-- ═══ Romans Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Romans', 6, 'kids', 1, 'Should we keep sinning so that God gives us more grace?', 'No! God forbid — we should not continue in sin', 'Yes, more sin means more grace', 'It does not matter either way', 'Only a little sinning is fine', 'a', 'Romans 6:1-2 — "Shall we continue in sin, that grace may abound? God forbid. How shall we, that are dead to sin, live any longer therein?"'),
('Romans', 6, 'kids', 2, 'What does baptism picture according to Paul?', 'Being buried with Jesus and rising to walk in a new life', 'Taking a bath', 'Swimming in a river', 'Washing your clothes', 'a', 'Romans 6:4 — "Therefore we are buried with him by baptism into death: that like as Christ was raised up from the dead by the glory of the Father, even so we also should walk in newness of life."'),
('Romans', 6, 'kids', 3, 'What is the wages (payment) of sin?', 'Death', 'Riches', 'Happiness', 'Fame', 'a', 'Romans 6:23 — "For the wages of sin is death; but the gift of God is eternal life through Jesus Christ our Lord."'),
-- Teens
('Romans', 6, 'teens', 1, 'What does Paul say our old man was crucified with Christ for?', 'That the body of sin might be destroyed, that henceforth we should not serve sin', 'So we could keep sinning freely', 'So the law would be abolished', 'So we could earn our salvation', 'a', 'Romans 6:6 — "Knowing this, that our old man is crucified with him, that the body of sin might be destroyed, that henceforth we should not serve sin."'),
('Romans', 6, 'teens', 2, 'What should believers reckon (consider) themselves to be?', 'Dead indeed unto sin, but alive unto God through Jesus Christ our Lord', 'Dead to God and alive to sin', 'Neither alive nor dead', 'Alive to both sin and God equally', 'a', 'Romans 6:11 — "Likewise reckon ye also yourselves to be dead indeed unto sin, but alive unto God through Jesus Christ our Lord."'),
('Romans', 6, 'teens', 3, 'What should believers yield their members (bodies) as?', 'Instruments of righteousness unto God', 'Instruments of sin and selfishness', 'Tools for worldly success', 'Weapons for political power', 'a', 'Romans 6:13 — "Neither yield ye your members as instruments of unrighteousness unto sin: but yield yourselves unto God... and your members as instruments of righteousness unto God."'),
('Romans', 6, 'teens', 4, 'What are believers now servants (slaves) of?', 'Righteousness — having been set free from sin', 'Sin — having been set free from righteousness', 'No one at all', 'Only themselves', 'a', 'Romans 6:18 — "Being then made free from sin, ye became the servants of righteousness."'),
('Romans', 6, 'teens', 5, 'What is the gift of God contrasted with the wages of sin?', 'Eternal life through Jesus Christ our Lord', 'A long life on earth', 'Material prosperity', 'Freedom from all trouble', 'a', 'Romans 6:23 — "For the wages of sin is death; but the gift of God is eternal life through Jesus Christ our Lord."'),
-- Adults
('Romans', 6, 'adults', 1, 'How does Paul refute the idea that grace encourages sin (antinomianism)?', 'Believers have died to sin through union with Christ in His death — they cannot continue living in what they died to', 'He ignores the objection', 'He admits grace may lead to more sin', 'He restricts grace to avoid the problem', 'a', 'Romans 6:2-3 — "God forbid. How shall we, that are dead to sin, live any longer therein? Know ye not, that so many of us as were baptized into Jesus Christ were baptized into his death?"'),
('Romans', 6, 'adults', 2, 'What does baptism symbolise in Paul''s theology?', 'Union with Christ in His death, burial, and resurrection — the believer''s identification with Christ''s redemptive work', 'A mere ritual washing', 'Membership in a church organisation', 'A public declaration with no deeper meaning', 'a', 'Romans 6:3-4 — "Buried with him by baptism into death: that like as Christ was raised up from the dead by the glory of the Father, even so we also should walk in newness of life."'),
('Romans', 6, 'adults', 3, 'What does "our old man is crucified with him" mean?', 'The believer''s former unregenerate self was judicially put to death with Christ so that the power of sin over the body is broken', 'The physical body dies at conversion', 'Believers never struggle with sin again', 'The old nature ceases to exist entirely', 'a', 'Romans 6:6 — "Knowing this, that our old man is crucified with him, that the body of sin might be destroyed, that henceforth we should not serve sin."'),
('Romans', 6, 'adults', 4, 'What logical argument does Paul make from Christ''s resurrection in verse 9?', 'Christ being raised from the dead dieth no more; death hath no more dominion over Him — and since believers are united with Him, sin has no dominion over them either', 'Christ might die again', 'Resurrection is repeatable', 'Death still has power over Christ', 'a', 'Romans 6:9 — "Knowing that Christ being raised from the dead dieth no more; death hath no more dominion over him."'),
('Romans', 6, 'adults', 5, 'What does "sin shall not have dominion over you" depend on?', 'Being under grace, not under law — grace provides both the motive and the power to overcome sin', 'Strict law-keeping', 'Human willpower alone', 'Avoiding all temptation', 'a', 'Romans 6:14 — "For sin shall not have dominion over you: for ye are not under the law, but under grace."'),
('Romans', 6, 'adults', 6, 'How does Paul use the slave-master metaphor to explain sanctification?', 'Just as a slave obeys one master, believers have changed masters — from sin (leading to death) to obedience (leading to righteousness)', 'Believers serve two masters simultaneously', 'Believers have no master at all', 'Slavery is endorsed as a social institution', 'a', 'Romans 6:16-18 — "Know ye not, that to whom ye yield yourselves servants to obey, his servants ye are... Being then made free from sin, ye became the servants of righteousness."'),
('Romans', 6, 'adults', 7, 'What is the "fruit" of the old life versus the new life?', 'The old life produced things they are now ashamed of, ending in death; the new life produces fruit unto holiness, ending in everlasting life', 'Both lives produce the same fruit', 'The old life was productive and good', 'The new life has no visible results', 'a', 'Romans 6:21-22 — "What fruit had ye then in those things whereof ye are now ashamed? for the end of those things is death. But now being made free from sin... ye have your fruit unto holiness, and the end everlasting life."'),
('Romans', 6, 'adults', 8, 'Why does Paul use the word "wages" for sin but "gift" for eternal life?', 'Sin pays what is earned and deserved (death); but eternal life is unearned — a free gift (charisma) of God through Jesus Christ', 'Both are earned equally', 'Death is also a gift', 'Eternal life is also wages', 'a', 'Romans 6:23 — "For the wages of sin is death; but the gift of God is eternal life through Jesus Christ our Lord." The deliberate contrast between earned wages and free gift encapsulates the gospel.');

-- ═══ Romans Chapter 7 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Romans', 7, 'kids', 1, 'Did Paul say the law is bad?', 'No, the law is holy, just, and good', 'Yes, the law is terrible', 'The law does not matter', 'The law is only for children', 'a', 'Romans 7:12 — "Wherefore the law is holy, and the commandment holy, and just, and good."'),
('Romans', 7, 'kids', 2, 'What struggle did Paul describe about doing right?', 'The good that he wanted to do, he did not do; and the bad he did not want to do, he kept doing', 'He always did the right thing perfectly', 'He never had any struggle', 'He only did bad things', 'a', 'Romans 7:19 — "For the good that I would I do not: but the evil which I would not, that I do."'),
('Romans', 7, 'kids', 3, 'Who did Paul say could rescue him from this struggle?', 'Jesus Christ our Lord', 'A powerful king', 'A wise teacher', 'He could rescue himself', 'a', 'Romans 7:25 — "I thank God through Jesus Christ our Lord."'),
-- Teens
('Romans', 7, 'teens', 1, 'What illustration does Paul use from marriage law to explain freedom from the law?', 'A woman is bound to her husband while he lives, but free when he dies — likewise believers have died to the law through Christ''s body', 'Marriage has nothing to do with the law', 'Divorce frees people from all obligations', 'Widows must never remarry', 'a', 'Romans 7:2-4 — "For the woman which hath an husband is bound by the law to her husband so long as he liveth; but if the husband be dead, she is loosed from the law of her husband."'),
('Romans', 7, 'teens', 2, 'What did the law cause sin to do in Paul?', 'It produced all manner of evil desire — for without the law, sin was dead', 'It stopped all sin permanently', 'It had no effect on sin', 'It made sin disappear', 'a', 'Romans 7:8 — "But sin, taking occasion by the commandment, wrought in me all manner of concupiscence. For without the law sin was dead."'),
('Romans', 7, 'teens', 3, 'What commandment did Paul cite as an example?', 'Thou shalt not covet', 'Thou shalt not kill', 'Thou shalt not steal', 'Remember the sabbath', 'a', 'Romans 7:7 — "I had not known sin, but by the law: for I had not known lust, except the law had said, Thou shalt not covet."'),
('Romans', 7, 'teens', 4, 'What does Paul say about his inner man versus his flesh?', 'He delights in the law of God after the inward man, but sees another law in his members warring against the law of his mind', 'His inner man and flesh are in perfect harmony', 'His flesh always wins completely', 'There is no conflict in the Christian life', 'a', 'Romans 7:22-23 — "For I delight in the law of God after the inward man: But I see another law in my members, warring against the law of my mind."'),
('Romans', 7, 'teens', 5, 'What cry does Paul make at the climax of his struggle?', 'O wretched man that I am! who shall deliver me from the body of this death?', 'I am perfect and need no help', 'I have conquered all sin by myself', 'There is no real problem to solve', 'a', 'Romans 7:24 — "O wretched man that I am! who shall deliver me from the body of this death?"'),
-- Adults
('Romans', 7, 'adults', 1, 'How does Paul''s marriage analogy in verses 1-4 establish freedom from the law?', 'Just as death dissolves a marriage bond, believers have died to the law through the body of Christ, freeing them to be joined to the risen Christ and bear fruit unto God', 'Believers divorce the law through a legal process', 'The law itself died', 'Marriage is abolished for Christians', 'a', 'Romans 7:4 — "Wherefore, my brethren, ye also are become dead to the law by the body of Christ; that ye should be married to another, even to him who is raised from the dead, that we should bring forth fruit unto God."'),
('Romans', 7, 'adults', 2, 'What does Paul mean by "the motions of sins, which were by the law, did work in our members"?', 'The law, rather than restraining sin, actually aroused sinful passions — the prohibition provoked the very desire it forbade', 'The law successfully prevented all sin', 'Sin existed independently of the law', 'The law created sin out of nothing', 'a', 'Romans 7:5 — "For when we were in the flesh, the motions of sins, which were by the law, did work in our members to bring forth fruit unto death."'),
('Romans', 7, 'adults', 3, 'Is the law sin? How does Paul answer this?', 'God forbid — the law is not sin, but it reveals sin; Paul would not have known coveting except through the commandment', 'Yes, the law is inherently sinful', 'The law is irrelevant to sin', 'The question should never be asked', 'a', 'Romans 7:7 — "What shall we say then? Is the law sin? God forbid. Nay, I had not known sin, but by the law."'),
('Romans', 7, 'adults', 4, 'How does Paul describe sin''s use of the commandment?', 'Sin, taking occasion by the commandment, deceived him and by it slew him — sin is personified as a deceiver that hijacks the good law', 'Sin and the commandment work together', 'The commandment is itself sinful', 'Sin ignores the commandment entirely', 'a', 'Romans 7:11 — "For sin, taking occasion by the commandment, deceived me, and by it slew me."'),
('Romans', 7, 'adults', 5, 'What theological truth does Paul establish about the nature of the law in verse 14?', 'The law is spiritual, but I am carnal, sold under sin — the problem is not the law but fallen human nature', 'The law is carnal and man is spiritual', 'Both the law and man are equally flawed', 'The law has no spiritual dimension', 'a', 'Romans 7:14 — "For we know that the law is spiritual: but I am carnal, sold under sin."'),
('Romans', 7, 'adults', 6, 'What is the "law of sin" that Paul identifies in verse 23?', 'A principle of indwelling sin operating in his members, warring against the law of his mind and bringing him into captivity', 'A literal legal code requiring sinning', 'A Jewish tradition about sin', 'An external force imposed by Satan alone', 'a', 'Romans 7:23 — "But I see another law in my members, warring against the law of my mind, and bringing me into captivity to the law of sin which is in my members."'),
('Romans', 7, 'adults', 7, 'Is Paul describing his pre-conversion or post-conversion experience in verses 14-25? What are the arguments?', 'The use of present tense, the delight in God''s law, and the struggle with indwelling sin strongly suggest Paul describes the ongoing struggle of a regenerate believer — though some argue it is pre-conversion or a rhetorical device', 'It is exclusively pre-conversion experience', 'It describes someone who was never a believer', 'It has no theological significance', 'a', 'Romans 7:22,25 — "I delight in the law of God after the inward man... So then with the mind I myself serve the law of God." The delight in God''s law and serving it with the mind point to regenerate experience.'),
('Romans', 7, 'adults', 8, 'How does verse 25 serve as a transition to chapter 8?', 'Paul thanks God through Jesus Christ — acknowledging that while the struggle with indwelling sin remains, deliverance comes through Christ, leading to the triumph declared in chapter 8', 'Verse 25 is unrelated to chapter 8', 'It concludes the entire argument of Romans', 'It introduces a new unrelated topic', 'a', 'Romans 7:25 — "I thank God through Jesus Christ our Lord." This thanksgiving points forward to chapter 8''s declaration of no condemnation and life in the Spirit.');

-- ═══ Romans Chapter 8 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Romans', 8, 'kids', 1, 'Is there any condemnation for those who are in Christ Jesus?', 'No, there is no condemnation', 'Yes, there is still condemnation', 'Only a little condemnation', 'Only for some people', 'a', 'Romans 8:1 — "There is therefore now no condemnation to them which are in Christ Jesus."'),
('Romans', 8, 'kids', 2, 'What does the Spirit of God help us call God?', 'Abba, Father — meaning dear Father', 'Master', 'King', 'Judge', 'a', 'Romans 8:15 — "Ye have received the Spirit of adoption, whereby we cry, Abba, Father."'),
('Romans', 8, 'kids', 3, 'Can anything separate us from God''s love?', 'No, nothing can separate us from the love of God in Christ Jesus', 'Yes, many things can', 'Only our own sins can', 'Yes, if we are not good enough', 'a', 'Romans 8:38-39 — "For I am persuaded, that neither death, nor life... shall be able to separate us from the love of God, which is in Christ Jesus our Lord."'),
-- Teens
('Romans', 8, 'teens', 1, 'What could the law not do, and what did God do instead?', 'What the law could not do because of the weakness of the flesh, God did by sending His own Son to condemn sin in the flesh', 'The law did everything perfectly', 'God strengthened the law instead', 'The law was replaced by a new set of rules', 'a', 'Romans 8:3 — "For what the law could not do, in that it was weak through the flesh, God sending his own Son in the likeness of sinful flesh, and for sin, condemned sin in the flesh."'),
('Romans', 8, 'teens', 2, 'What does it mean to be carnally minded versus spiritually minded?', 'To be carnally minded is death, but to be spiritually minded is life and peace', 'Both are equally good', 'Carnal mindedness is better for daily life', 'Spiritual mindedness only matters after death', 'a', 'Romans 8:6 — "For to be carnally minded is death; but to be spiritually minded is life and peace."'),
('Romans', 8, 'teens', 3, 'What does Paul say all things work together for?', 'Good to them that love God, to them who are the called according to His purpose', 'Harm to believers', 'Wealth and earthly success', 'Only spiritual things, not practical ones', 'a', 'Romans 8:28 — "And we know that all things work together for good to them that love God, to them who are the called according to his purpose."'),
('Romans', 8, 'teens', 4, 'If God be for us, who can be against us?', 'No one can successfully stand against us — He that spared not His own Son will freely give us all things', 'Many people can be effectively against us', 'God is not always for us', 'Only the strong can be against us', 'a', 'Romans 8:31-32 — "If God be for us, who can be against us? He that spared not his own Son, but delivered him up for us all, how shall he not with him also freely give us all things?"'),
('Romans', 8, 'teens', 5, 'What is the list of things that cannot separate us from God''s love?', 'Death, life, angels, principalities, powers, things present, things to come, height, depth, nor any other creature', 'Only a few small things', 'Everything except death', 'Nothing is listed specifically', 'a', 'Romans 8:38-39 — "For I am persuaded, that neither death, nor life, nor angels, nor principalities, nor powers, nor things present, nor things to come, Nor height, nor depth, nor any other creature, shall be able to separate us from the love of God."'),
-- Adults
('Romans', 8, 'adults', 1, 'What does "no condemnation" in verse 1 mean in context of Paul''s argument?', 'After establishing universal guilt (ch.1-3), justification by faith (ch.3-5), and the believer''s struggle with sin (ch.7), Paul declares that those in Christ face no judicial condemnation — their legal standing before God is fully secure', 'Believers will never experience any difficulty', 'Sin no longer exists for Christians', 'Condemnation is merely postponed', 'a', 'Romans 8:1 — "There is therefore now no condemnation to them which are in Christ Jesus." This is the triumphant conclusion: justified believers stand free from God''s condemning verdict.'),
('Romans', 8, 'adults', 2, 'What is the "law of the Spirit of life" that has freed believers?', 'The governing principle of the Holy Spirit''s life-giving power, which overcomes the principle of sin and death operating in fallen human nature', 'A new set of written commandments', 'The Mosaic law reinterpreted', 'A physical law of nature', 'a', 'Romans 8:2 — "For the law of the Spirit of life in Christ Jesus hath made me free from the law of sin and death."'),
('Romans', 8, 'adults', 3, 'What does Paul teach about the Holy Spirit''s role in assurance of salvation?', 'The Spirit itself beareth witness with our spirit that we are the children of God — providing internal testimony of our adoption', 'The Spirit has no role in assurance', 'Assurance comes only from good works', 'Assurance is impossible to have', 'a', 'Romans 8:16 — "The Spirit itself beareth witness with our spirit, that we are the children of God."'),
('Romans', 8, 'adults', 4, 'What does Paul say about present sufferings compared to future glory?', 'The sufferings of this present time are not worthy to be compared with the glory which shall be revealed in us', 'Present sufferings outweigh future glory', 'There will be no future glory', 'Sufferings and glory are equal', 'a', 'Romans 8:18 — "For I reckon that the sufferings of this present time are not worthy to be compared with the glory which shall be revealed in us."'),
('Romans', 8, 'adults', 5, 'What does Paul say creation is waiting for?', 'The manifestation of the sons of God — when believers are glorified and creation itself is delivered from the bondage of corruption', 'The destruction of the world', 'A new government', 'The end of all animal life', 'a', 'Romans 8:19,21 — "For the earnest expectation of the creature waiteth for the manifestation of the sons of God... the creature itself also shall be delivered from the bondage of corruption into the glorious liberty of the children of God."'),
('Romans', 8, 'adults', 6, 'What is the "golden chain of salvation" in verses 29-30?', 'Foreknew, predestinated, called, justified, glorified — an unbreakable chain from God''s eternal purpose to the believer''s final glorification', 'A chain of human achievement', 'A suggestion of possible outcomes', 'A description of angels'' ranks', 'a', 'Romans 8:29-30 — "For whom he did foreknow, he also did predestinate to be conformed to the image of his Son... Moreover whom he did predestinate, them he also called: and whom he called, them he also justified: and whom he justified, them he also glorified."'),
('Romans', 8, 'adults', 7, 'How does Paul use five rhetorical questions in verses 31-35 to establish the security of the believer?', 'Each question expects a resounding answer: no one can condemn (Christ intercedes), no one can separate (God''s love is supreme), nothing can defeat the purpose of God for His people', 'The questions express doubt about salvation', 'The questions are addressed to unbelievers', 'The questions have no clear answers', 'a', 'Romans 8:31-35 — "If God be for us, who can be against us?... Who shall lay any thing to the charge of God''s elect?... Who shall separate us from the love of Christ?" Each builds an unassailable case for eternal security.'),
('Romans', 8, 'adults', 8, 'How does Romans 8:28 relate to God''s sovereignty and human suffering?', 'God sovereignly orchestrates all circumstances — including suffering — to accomplish His good purpose for those who love Him and are called according to His purpose, conforming them to the image of His Son', 'God causes all suffering directly', 'Suffering is always punishment for sin', 'God is unaware of human suffering', 'a', 'Romans 8:28-29 — "All things work together for good to them that love God... to be conformed to the image of his Son." God''s providence encompasses all events, directing them toward the ultimate good of Christlikeness.');
